typedef float fp;

#ifndef MAX_WORKGROUP_SIZE
#define MAX_WORKGROUP_SIZE 1024
#endif

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        fp v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int d_blocks)
{
    (void)d_Ne;
    (void)d_blocks;

    size_t lid = get_local_id(0);
    size_t gid = get_global_id(0);
    size_t group = get_group_id(0);
    size_t lsize = get_local_size(0);

    __local fp lsum[MAX_WORKGROUP_SIZE];
    __local fp lsum2[MAX_WORKGROUP_SIZE];

    fp v1 = 0.0f;
    fp v2 = 0.0f;

    if ((long)gid < d_no) {
        long idx = (long)gid * (long)d_mul;
        v1 = d_sums[idx];
        v2 = d_sums2[idx];
    }

    lsum[lid] = v1;
    lsum2[lid] = v2;
    barrier(CLK_LOCAL_MEM_FENCE);

    for (size_t stride = lsize >> 1; stride > 0; stride >>= 1) {
        if (lid < stride) {
            lsum[lid] += lsum[lid + stride];
            lsum2[lid] += lsum2[lid + stride];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (lid == 0) {
        long out = (long)group * (long)d_mul * (long)lsize;
        d_sums[out] = lsum[0];
        d_sums2[out] = lsum2[0];
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *d_iN,
                          __global int *d_iS,
                          __global int *d_jE,
                          __global int *d_jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I)
{
    (void)lambda;
    (void)Nr;

    long k = (long)get_global_id(0);

    if (k < Ne) {
        int i = (int)(k / (long)Nc);
        int j = (int)(k % (long)Nc);

        fp Jc = d_I[k];

        d_dN[k] = d_I[(long)d_iN[i] * (long)Nc + j] - Jc;
        d_dS[k] = d_I[(long)d_iS[i] * (long)Nc + j] - Jc;
        d_dW[k] = d_I[(long)i * (long)Nc + d_jW[j]] - Jc;
        d_dE[k] = d_I[(long)i * (long)Nc + d_jE[j]] - Jc;

        fp G2 = (d_dN[k] * d_dN[k] +
                 d_dS[k] * d_dS[k] +
                 d_dW[k] * d_dW[k] +
                 d_dE[k] * d_dE[k]) / (Jc * Jc);

        fp L = (d_dN[k] + d_dS[k] + d_dW[k] + d_dE[k]) / Jc;

        fp num = (0.5f * G2) - (0.0625f * L * L);
        fp den = 1.0f + 0.25f * L;
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        fp c = 1.0f / (1.0f + den);

        if (c < 0.0f) {
            c = 0.0f;
        } else if (c > 1.0f) {
            c = 1.0f;
        }

        d_c[k] = c;
    }
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *d_iN,
                           __global int *d_iS,
                           __global int *d_jE,
                           __global int *d_jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I)
{
    (void)Nr;
    (void)d_iN;
    (void)d_jW;

    long k = (long)get_global_id(0);

    if (k < Ne) {
        int i = (int)(k / (long)Nc);
        int j = (int)(k % (long)Nc);

        fp cN = d_c[k];
        fp cS = d_c[(long)d_iS[i] * (long)Nc + j];
        fp cW = d_c[k];
        fp cE = d_c[(long)i * (long)Nc + d_jE[j]];

        fp D = cN * d_dN[k] +
               cS * d_dS[k] +
               cW * d_dW[k] +
               cE * d_dE[k];

        d_I[k] = d_I[k] + 0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I)
{
    long ei = (long)get_global_id(0);

    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
}
